1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const RUNE_BLOCK_SIZE = 3;
14	const RUNE_BLOCK_PRICE = 60;
15	
16	interface Item {
17	  type: string;
18	}
19	
20	interface QuoteStep {
21	  op: "quote";
22	  items: Item[];
23	}
24	
25	interface Scenario {
26	  customer: { yearsWithMHPCO: number };
27	  steps: QuoteStep[];
28	}
29	
30	export function runScenario(input: unknown): unknown {
31	  const scenario = input as Scenario;
32	  const results = scenario.steps.map((step) => {
33	    const countsByType: Record<string, number> = {};
34	    for (const item of step.items) {
35	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
36	    }
37	    let basePremium = 0;
38	    for (const [type, count] of Object.entries(countsByType)) {
39	      if (type === "rune" && count === RUNE_BLOCK_SIZE) {
40	        basePremium += RUNE_BLOCK_PRICE;
41	      } else {
42	        const perItem = BASE_PREMIUM[type] ?? 0;
43	        basePremium += perItem * count;
44	      }
45	    }
46	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
47	    const rawPremium = basePremium + firstInsurance + PROCESSING_FEE;
48	    const premium = Math.ceil(rawPremium);
49	    return { premium };
50	  });
51	  return { results };
52	}
